244→func generateJWT(authHandle *auth.Authentication, username string) error {
245→	ur := repository.GetUserRepository()
246→	user, err := ur.GetUser(username)
247→	if err != nil {
248→		return fmt.Errorf("getting user '%s': %w", username, err)
249→	}
250→
251→	if !user.HasRole(schema.RoleAPI) {
252→		cclog.Warnf("JWT: User '%s' does not have the role 'api'. REST API endpoints will return error!\n", user.Username)
253→	}
254→
255→	jwt, err := authHandle.JwtAuth.ProvideJWT(user)
256→	if err != nil {
257→		return fmt.Errorf("generating JWT for user '%s': %w", user.Username, err)
258→	}
